// Build system and user prompts based on content type
const contentType = $json['Content Type'] || $json.contentType || 'linkedin-post';
const topic = $json['Topic'] || $json.topic || '';
const audience = $json['Audience'] || $json.audience || 'UK SMEs (10-100 employees) in the defence supply chain';
const additionalContext = $json['Additional Context'] || $json.additionalContext || '';

const brandContext = `## CertPilot Brand Context
- Product: CertPilot - Multi-framework compliance platform for UK SMEs
- Frameworks: Def Stan 05-138, ISO 27001, SOC 2, IASME Governance, Cyber Essentials, DCC (Levels 0-3)
- Target: UK SMEs (10-100 employees) in the defence supply chain
- Key stats: 410+ controls mapped, 70% evidence reuse between frameworks
- DEFCON 658 deadline makes DCC mandatory for MOD suppliers
- Brand voice: Clear, confident, warm, action-oriented
- ALWAYS use UK spelling (defence, organisation, behaviour, recognise)
- Tone: Practitioner, not vendor marketing`;

const typePrompts = {
  'linkedin-post': {
    system: `You are a senior LinkedIn content strategist for CertPilot.

${brandContext}

## LinkedIn Post Rules
- 150-250 words per post
- 3-5 relevant hashtags at the end
- Strong hook in the first 2 lines
- NEVER open with generic phrases ("Excited to share", "In today's world")
- Write as a thought leader, not a software vendor
- Include a clear call-to-action or question
- Use line breaks for readability`,
    user: `Write a LinkedIn post about: ${topic}

Target audience: ${audience}
${additionalContext ? '
Additional context: ' + additionalContext : ''}

Provide 2 options:
- Option 1: Insight/thought leadership angle
- Option 2: Educational/practical angle

Each option should be 150-250 words with hashtags.`
  },
  'blog-outline': {
    system: `You are a content marketing strategist for CertPilot.

${brandContext}

## Blog Writing Rules
- Write for busy compliance/IT managers at SMEs
- Use clear headings and scannable structure
- Include practical takeaways, not just theory
- Reference specific frameworks and regulations
- SEO-aware: include target keywords naturally
- 800-1200 word target length for the final article
- UK English throughout`,
    user: `Create a detailed blog post outline about: ${topic}

Target audience: ${audience}
${additionalContext ? '
Additional context: ' + additionalContext : ''}

Provide:
1. **Title** (SEO-optimised, under 60 chars)
2. **Meta description** (under 160 chars)
3. **Target keywords** (3-5)
4. **Outline** with:
   - Introduction hook
   - 4-6 main sections with subheadings
   - Key points for each section
   - Practical takeaway or CTA
5. **Suggested internal links** to CertPilot features`
  },
  'email-draft': {
    system: `You are an email marketing specialist for CertPilot.

${brandContext}

## Email Rules
- Subject line under 50 chars, no spam trigger words
- Preview text that complements (not repeats) the subject
- Conversational but professional tone
- Single clear CTA per email
- Mobile-friendly: short paragraphs, clear hierarchy
- UK English throughout
- Compliant with UK GDPR / PECR`,
    user: `Draft a marketing email about: ${topic}

Target audience: ${audience}
${additionalContext ? '
Additional context: ' + additionalContext : ''}

Provide:
1. **Subject line** (A/B test: 2 options)
2. **Preview text**
3. **Email body** (250-400 words)
4. **CTA button text**
5. **P.S. line** (optional hook)`
  },
  'social-caption': {
    system: `You are a social media manager for CertPilot.

${brandContext}

## Social Caption Rules
- Platform-aware (adapt length and style)
- Punchy, scannable, value-first
- Include relevant hashtags
- Emojis: sparingly and purposefully
- UK English throughout
- Not salesy — informative and engaging`,
    user: `Write social media captions about: ${topic}

Target audience: ${audience}
${additionalContext ? '
Additional context: ' + additionalContext : ''}

Provide captions for:
1. **LinkedIn** (150-250 words, 3-5 hashtags)
2. **Twitter/X** (under 280 chars, 2-3 hashtags)
3. **Facebook** (100-150 words, conversational)

Each should have a distinct angle — don't just shorten the same text.`
  }
};

const prompts = typePrompts[contentType] || typePrompts['linkedin-post'];

return [{
  json: {
    contentType,
    topic,
    audience,
    additionalContext,
    systemPrompt: prompts.system,
    userPrompt: prompts.user
  }
}];

// Parse GLM-5 response and format output
const response = $input.item.json;
const contentType = $('Build Content Prompt').item.json.contentType;
const topic = $('Build Content Prompt').item.json.topic;

let generatedContent = '';
if (response.content && Array.isArray(response.content)) {
  generatedContent = response.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('\n');
} else if (typeof response === 'string') {
  generatedContent = response;
}

const inputTokens = response.usage?.input_tokens || 0;
const outputTokens = response.usage?.output_tokens || 0;

const contentTypeLabels = {
  'linkedin-post': 'LinkedIn Post',
  'blog-outline': 'Blog Outline',
  'email-draft': 'Email Draft',
  'social-caption': 'Social Captions'
};

const notificationText = `*Content Generated: ${contentTypeLabels[contentType] || contentType}*\nTopic: ${topic}\nTokens: ${inputTokens} in / ${outputTokens} out\n\n${generatedContent.substring(0, 3500)}${generatedContent.length > 3500 ? '\n\n_[Truncated]_' : ''}`;

return [{
  json: {
    contentType,
    topic,
    generatedContent,
    inputTokens,
    outputTokens,
    notificationText
  }
}];
